package com.taskmind.backend.task.infrastructure.persistence.jpa;
import com.taskmind.backend.task.domain.model.*; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="task_links") public class TaskLinkJpaEntity { @Id private UUID id; @Version private Long version; @Column(name="source_task_id") private UUID sourceTaskId; @Column(name="target_task_id") private UUID targetTaskId; @Enumerated(EnumType.STRING) @Column(name="link_type") private TaskLinkType linkType; @Column(name="created_by_user_id") private UUID createdByUserId; @Column(name="created_at") private Instant createdAt; protected TaskLinkJpaEntity(){} private TaskLinkJpaEntity(TaskLink l){id=l.id();version=l.version();sourceTaskId=l.sourceTaskId();targetTaskId=l.targetTaskId();linkType=l.linkType();createdByUserId=l.createdByUserId();createdAt=l.createdAt();} public static TaskLinkJpaEntity fromDomain(TaskLink l){return new TaskLinkJpaEntity(l);} public TaskLink toDomain(){return new TaskLink(id,version,sourceTaskId,targetTaskId,linkType,createdByUserId,createdAt);} }
